/**
 * Bitrefill firewall config generator.
 *
 * Data source: https://docs.bitrefill.com/
 *
 * Bitrefill Personal API authenticates with a Bearer token in the
 * Authorization header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.bitrefill.com/";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCof";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Bitrefill API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:bitrefill",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const bitrefillFirewall = {",
    '  name: "bitrefill",',
    '  description: "Bitrefill API",',
    "  placeholders: {",
    `    BITREFILL_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.bitrefill.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.BITREFILL_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Bitrefill firewall config...");
  const ts = generateTypeScript();
  writeOutput("bitrefill", ts, import.meta.dirname);
}
